/*!
 * \file pybind11.cpp
 * \brief PyBind11 bindings for GELU kernel
 */

#include <pybind11/pybind11.h>
#include <torch/extension.h>
#include <torch_npu/csrc/core/npu/NPUStream.h>

struct GeluTilingData {
    uint32_t totalElements;
    uint32_t blockSize;
    uint32_t usedCoreNum;
};

constexpr int32_t MAX_CORES = 8;

// Host launch stubs generated by AscendC compiler
extern "C" uint32_t aclrtlaunch_gelu_fp32(uint32_t blockDim, void* stream,
                                          void* x, void* y, void* workspace, void* tiling);
extern "C" uint32_t aclrtlaunch_gelu_fp16(uint32_t blockDim, void* stream,
                                          void* x, void* y, void* workspace, void* tiling);
extern "C" uint32_t aclrtlaunch_gelu_bf16(uint32_t blockDim, void* stream,
                                          void* x, void* y, void* workspace, void* tiling);

namespace gelu_op {

at::Tensor run_gelu(const at::Tensor &x)
{
    TORCH_CHECK(x.is_contiguous(), "Input tensor must be contiguous");
    TORCH_CHECK(
        x.scalar_type() == at::kFloat || x.scalar_type() == at::kHalf || x.scalar_type() == at::kBFloat16,
        "Input must be float16, float32, or bfloat16");

    const int64_t totalElements = x.numel();
    at::Tensor y = at::empty_like(x);

    constexpr uint32_t DEFAULT_BLOCK_SIZE = 256;
    const uint32_t blockSize = static_cast<uint32_t>(std::min<int64_t>(DEFAULT_BLOCK_SIZE, totalElements));
    const int32_t blockDim = std::min<int32_t>(
        static_cast<int32_t>((totalElements + blockSize - 1) / blockSize),
        MAX_CORES);

    // Prepare tiling data on host stack
    GeluTilingData tiling;
    tiling.totalElements = static_cast<uint32_t>(totalElements);
    tiling.blockSize = blockSize;
    tiling.usedCoreNum = static_cast<uint32_t>(blockDim);

    // Copy tiling struct to device memory (H2D) because GM_ADDR expects device pointer
    auto tilingCpu = torch::from_blob(
        &tiling,
        {static_cast<int64_t>(sizeof(GeluTilingData))},
        torch::TensorOptions().dtype(torch::kUInt8));
    auto tilingTensor = tilingCpu.to(x.device());

    void *xPtr = x.data_ptr();
    void *yPtr = y.data_ptr();
    void *tilingPtr = tilingTensor.data_ptr();

    // Get current NPU stream for kernel launch
    auto npuStream = c10_npu::getCurrentNPUStream();
    void *stream = npuStream.stream(false);

    // Dummy reference to ensure libtorch_npu.so is kept as a dependency
    (void)stream;

    // Select kernel based on dtype and launch via generated host stub
    uint32_t ret = 0;
    if (x.scalar_type() == at::kFloat) {
        ret = aclrtlaunch_gelu_fp32(blockDim, stream, xPtr, yPtr, nullptr, tilingPtr);
    } else if (x.scalar_type() == at::kHalf) {
        ret = aclrtlaunch_gelu_fp16(blockDim, stream, xPtr, yPtr, nullptr, tilingPtr);
    } else {
        ret = aclrtlaunch_gelu_bf16(blockDim, stream, xPtr, yPtr, nullptr, tilingPtr);
    }
    if (ret != 0) {
        TORCH_CHECK(false, "LaunchAscendKernel failed with ret=", ret);
    }

    return y;
}

}  // namespace gelu_op

PYBIND11_MODULE(gelu_op, m) {
    m.doc() = "GELU operator binding";
    m.def("run_gelu", &gelu_op::run_gelu, "GELU forward pass");
}
